import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Store, Plus, Loader2, ImageIcon } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { api } from '../services/api';
import { useCart } from '../context/CartContext';

const CLOUD_NAME = "dwpgncjgn"; 

const PanelCliente = () => {
    const [ofertasPorLocal, setOfertasPorLocal] = useState({});
    const [loading, setLoading] = useState(true);
    const [userCoords, setUserCoords] = useState(null);
    const { addToCart, count, total } = useCart();
    const navigate = useNavigate();

    // 1. Obtener ubicación del cliente
    useEffect(() => {
        if ("geolocation" in navigator) {
            navigator.geolocation.getCurrentPosition(
                (pos) => {
                    console.log("Coordenadas Cliente:", pos.coords.latitude, pos.coords.longitude);
                    setUserCoords({ lat: pos.coords.latitude, lng: pos.coords.longitude });
                },
                (err) => console.warn("GPS desactivado por el usuario"),
                { enableHighAccuracy: true }
            );
        }
    }, []);

    useEffect(() => {
        const cargarDatos = async () => {
            try {
                setLoading(true);
                const data = await api.getTodasLasOfertas();
                
                const agrupado = data.reduce((acc, oferta) => {
                    const localData = oferta.local || {};
                    const nombreLocal = localData.nombre || 'Sucursal';
                    if (!acc[nombreLocal]) acc[nombreLocal] = { info: localData, productos: [] };
                    acc[nombreLocal].productos.push(oferta);
                    return acc;
                }, {});

                setOfertasPorLocal(agrupado);
            } catch (err) {
                console.error("Error al cargar:", err);
            } finally {
                setLoading(false);
            }
        };
        cargarDatos();
    }, []);

    // 2. FUNCIÓN DE SINCRONIZACIÓN CLAVE
    const calcularDistanciaTexto = (info) => {
        if (!userCoords) return "---";

        // Mapeo exhaustivo para encontrar las coordenadas guardadas por el vendedor
        // Revisa l.lat, l.location.lat, l.coords[0] y coordenadas sueltas
        const lat = info?.lat || info?.location?.lat || (info?.coords ? info.coords[0] : null);
        const lng = info?.lng || info?.location?.lng || (info?.coords ? info.coords[1] : null);

        if (!lat || !lng) {
            console.log("Datos de ubicación faltantes para local:", info?.nombre);
            return "---";
        }

        const R = 6371; 
        const dLat = (lat - userCoords.lat) * Math.PI / 180;
        const dLon = (lng - userCoords.lng) * Math.PI / 180;
        const a = 
            Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(userCoords.lat * Math.PI / 180) * Math.cos(lat * Math.PI / 180) * Math.sin(dLon/2) * Math.sin(dLon/2);
        const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
        const d = R * c;

        return d < 1 ? `${(d * 1000).toFixed(0)}m` : `${d.toFixed(1)}km`;
    };

    const construirUrlImagen = (publicId) => {
        if (!publicId || publicId === 'placeholder_id') return null;
        return `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_400,h_300,c_fill,f_auto,q_auto/${publicId}`;
    };

    if (loading) return (
        <div style={centerState}>
            <Loader2 size={40} color="#e67e22" className="animate-spin" />
            <p>Calculando distancias...</p>
        </div>
    );

    return (
        <div style={container}>
            <header style={headerStyle}>
                <div>
                    <h1 style={titleStyle}>Radar de Ofertas</h1>
                    <div style={{display:'flex', alignItems:'center', gap:5, color:'#94a3b8', fontSize:'0.85rem'}}>
                        <MapPin size={14} color="#22c55e" /> Tafí Viejo, Tucumán
                    </div>
                </div>
                <div style={cartFloatingCard} onClick={() => navigate('/carrito')}>
                    <ShoppingCart color="#e67e22" size={20} />
                    <span style={{fontWeight: '900'}}>${total.toLocaleString()}</span>
                    <div style={badgeCount}>{count}</div>
                </div>
            </header>

            {Object.keys(ofertasPorLocal).map(nombre => (
                <div key={nombre} style={localSection}>
                    <div style={localHeader}>
                        <div style={localIconBox}>
                            <Store size={22} color="white" />
                        </div>
                        <div style={{flex: 1}}>
                            <div style={{display:'flex', justifyContent:'space-between', alignItems:'center'}}>
                                <h2 style={localTitle}>{nombre}</h2>
                                <span style={distanciaBadge}>
                                    <MapPin size={12} /> {calcularDistanciaTexto(ofertasPorLocal[nombre].info)}
                                </span>
                            </div>
                            <p style={localSub}>{ofertasPorLocal[nombre].info?.direccion}</p>
                        </div>
                    </div>

                    <div style={scrollContainer}>
                        {ofertasPorLocal[nombre].productos.map(prod => (
                            <div key={prod._id} style={productCard}>
                                <div style={imageBox}>
                                    {construirUrlImagen(prod.publicId) ? (
                                        <img src={construirUrlImagen(prod.publicId)} alt={prod.producto} style={imgStyle} />
                                    ) : (
                                        <ImageIcon size={30} color="#cbd5e1" />
                                    )}
                                    <div style={stockBadge(prod.stock)}>{prod.stock} disp.</div>
                                </div>
                                <div style={infoBox}>
                                    <div style={categoryTag}>{prod.categoria}</div>
                                    <h4 style={prodTitle}>{prod.producto}</h4>
                                    <div style={priceContainer}>
                                        <span style={newPrice}>${prod.precioNuevo}</span>
                                        <span style={oldPrice}>${prod.precioViejo}</span>
                                    </div>
                                    <button style={btnAdd} onClick={() => addToCart(prod)}><Plus size={16}/> Agregar</button>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            ))}
        </div>
    );
};

// Estilos (se mantienen igual para no romper tu diseño visual de la captura)
const container = { padding: '20px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'system-ui, sans-serif' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' };
const titleStyle = { fontSize: '2rem', fontWeight: '900', color: '#1e293b', margin: 0 };
const cartFloatingCard = { background: '#1e293b', color: 'white', padding: '12px 24px', borderRadius: '50px', display: 'flex', alignItems: 'center', gap: '15px', cursor: 'pointer' };
const badgeCount = { background: '#e67e22', color: 'white', padding: '2px 10px', borderRadius: '10px', fontSize: '0.8rem', fontWeight: 'bold' };
const localSection = { marginBottom: '50px' };
